package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.RekenElement;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import com.google.common.collect.Sets;

import java.util.Collection;
import java.util.HashSet;

public class LoonCodeTools {

    private static final HashSet<Integer> GEWOONLOON_CODES = Sets.newHashSet(CodeExtensie.GEWOON_LOON.getCode(), CodeExtensie.MANDATARIS_WEDDE.getCode());

    private static final HashSet<CodeExtensie> CODES_GRENS_GEBOORTE_VERLOF =
            Sets.newHashSet(CodeExtensie.PLEEG_ZORG_VERLOF_VBN_131_3, CodeExtensie.PLEEG_ZORG_VERLOF_VBN_133_2, CodeExtensie.GEBOORTE_VERLOF_VBN_134_1);

    public static boolean isGeval170(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getTijdperk() == AkeTijdperk.DMFAPPL.getCode().intValue() && aardKodeExtensie.getAard() == AardKodeExt.V_KODE_EXT
                .getCode().intValue() && (matches(aardKodeExtensie, CodeExtensie.GEWOON_LOON_170) || matches(aardKodeExtensie,
                CodeExtensie.GEWOON_LOON_EXT_171));
    }

    public static boolean isArbeidsOngeval(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getTijdperk() == AkeTijdperk.DMFAPPL.getCode().intValue() && aardKodeExtensie.getAard() == AardKodeExt.S_KODE_EXT
                .getCode().intValue() && (matches(aardKodeExtensie, CodeExtensie.ARBEIDSONGEVAL) || matches(aardKodeExtensie,
                CodeExtensie.TERUGVORDERING_ARBEIDSONGEVAL));
    }

    public static boolean isPremieBijzondereBeroepsbekwaamheid(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getTijdperk() == AkeTijdperk.DMFAPPL.getCode().intValue() && aardKodeExtensie.getAard() == AardKodeExt.S_KODE_EXT
                .getCode().intValue() && matches(aardKodeExtensie, CodeExtensie.PREMIE_BIJZONDERE_BEROEPSBEKWAAMHEID);
    }

    public static boolean isPremieBijzondereBeroepstitel(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getTijdperk() == AkeTijdperk.DMFAPPL.getCode().intValue() && aardKodeExtensie.getAard() == AardKodeExt.S_KODE_EXT
                .getCode().intValue() && matches(aardKodeExtensie, CodeExtensie.PREMIE_BIJZONDERE_BEROEPSTITEL);
    }

    public static boolean isAttractiviteitsPremie(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getTijdperk() == AkeTijdperk.DMFAPPL.getCode().intValue() && aardKodeExtensie.getAard() == AardKodeExt.S_KODE_EXT
                .getCode().intValue() && (matches(aardKodeExtensie, CodeExtensie.ATTRACTIVITEITSPREMIE_1) || matches(aardKodeExtensie,
                CodeExtensie.ATTRACTIVITEITSPREMIE_2));
    }

    public static boolean isBrugPensioen(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getTijdperk() == AkeTijdperk.DMFAPPL.getCode().intValue() && aardKodeExtensie.getAard() == AardKodeExt.S_KODE_EXT
                .getCode().intValue() && (matches(aardKodeExtensie, CodeExtensie.BRUG_PENSIOEN_1) || matches(aardKodeExtensie,
                CodeExtensie.BRUG_PENSIOEN_2));
    }

    public static boolean isFictieveAkeDoelgroepVerminderingen(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getTijdperk() == AkeTijdperk.DMFAPPL.getCode().intValue() && aardKodeExtensie.getAard() == AardKodeExt.S_KODE_EXT
                .getCode().intValue() && matches(aardKodeExtensie, CodeExtensie.FICTIEVE_AKE_DOELGROEP_VERM);
    }

    public static boolean matches(AardKodeExtensie aardKodeExtensie, CodeExtensie codeExtensie) {
        return aardKodeExtensie.getCode() == codeExtensie.getCode() && aardKodeExtensie.getExtensie() == codeExtensie.getExtensie();
    }

    public static boolean matches(AardKodeExtensie aardKodeExtensie, Collection<CodeExtensie> codeExtensies) {
        return matches(aardKodeExtensie.getCode(), aardKodeExtensie.getExtensie(), codeExtensies);
    }

    public static boolean matches(Integer code, Integer extensie, Collection<CodeExtensie> codeExtensies) {
        return codeExtensies.stream().anyMatch(x -> matches(code, extensie, x));
    }

    public static boolean matches(Integer code, Integer extensie, CodeExtensie codeExtensie) {
        return code == codeExtensie.getCode() && extensie == codeExtensie.getExtensie();
    }

    public static boolean matches(RekenElement rekenElement, Collection<CodeExtensie> codeExtensies) {
        return matches(rekenElement.getCode(), rekenElement.getExtensie(), codeExtensies);
    }

    public static boolean matches(NlpPrestatie prestatie, CodeExtensie codeExtensie) {
        return matches(prestatie.getCode(), prestatie.getExtensie(), codeExtensie);
    }

    public static boolean isOvermachtStatutair(AardKodeExtensie loonCode) {
        return AkeTijdperk.DMFAPPL.getCode().equals(loonCode.getTijdperk()) && loonCode.getAard() == 1 && loonCode.getCode() == 135 && loonCode.getExtensie() == 2;
    }

    public static boolean isFictieveGeboorteTeller(AardKodeExtensie loonCode) {
        return AkeTijdperk.DMFAPPL.getCode().equals(loonCode.getTijdperk()) && loonCode.getAard() == 1 &&
                matches(loonCode.getCode(), loonCode.getExtensie(), CODES_GRENS_GEBOORTE_VERLOF);
    }

    public static boolean isGewoonLoon(AardKodeExtensie extensie) {
        return GEWOONLOON_CODES.contains(extensie.getCode());
    }

    public static boolean isWachtgeldAmbtsontheffing(AardKodeExtensie loonCode) {
        return AkeTijdperk.DMFAPPL.getCode().equals(loonCode.getTijdperk()) && loonCode.getAard() == 1 && (loonCode.getCode() == 151 || loonCode.getCode() == 154) &&
                loonCode.getExtensie() == 1;
    }

    public static boolean isAanvullendeEuropeseVakantieDag(AardKodeExtensie loonCode) {
        return AkeTijdperk.DMFAPPL.getCode().equals(loonCode.getTijdperk()) && loonCode.getAard() == 1 && loonCode.getCode() == 105 && loonCode.getExtensie() == 11;
    }

    public static boolean isWeeken80pct(AardKodeExtensie loonCode) {
        return AkeTijdperk.DMFAPPL.getCode().equals(loonCode.getTijdperk()) && loonCode.getAard() == 1 && loonCode.getCode() == 102 && loonCode.getExtensie() == 8;
    }
}
